urlset:

  {{ request.url_root }}
  weekly


  {{ request.url_root }}blog/
  weekly

{% for post in posts %}

  {{ request.url_root }}posts/{{ post.slug }}/
  {{ post.date }}
  yearly

{% endfor %}
{% for tag in tags %}

  {{ request.url_root }}blog/tag/{{ tag.slug }}/
  {% if tag_lastmod[tag.slug] %}
  {{ tag_lastmod[tag.slug] }}
  {% endif %}
  monthly

{% endfor %}
{% for year in years %}

  {{ request.url_root }}blog/year/{{ year }}/
  {% if year_lastmod[year] %}
  {{ year_lastmod[year] }}
  {% endif %}
  yearly

{% endfor %}
